## CLI Interface

```rust
use clap::ValueEnum;

#[derive(Debug, Clone, Copy, ValueEnum)]
pub enum Preset {
    /// Conservative: only high-confidence edits (0.8)
    Strict,
    /// Balanced: reasonable confidence threshold (0.5) [default]
    Normal,
    /// Aggressive: accept lower-confidence edits (0.3)
    Aggressive,
    /// Accept almost any edit (0.1)
    Relaxed,
}

#[derive(Parser, Debug)]
pub struct Config {
    /// Confidence threshold preset
    #[arg(long, short = 'P', value_enum, conflicts_with = "min_score")]
    pub preset: Option<Preset>,

    /// Minimum confidence score (0.0-1.0) for applying edits
    #[arg(long, short = 's', default_value = "0.5")]
    pub min_score: f64,
}
```

**Usage:**
```bash
aadc --preset strict diagram.txt      # Only high-confidence edits
aadc --preset normal diagram.txt      # Default behavior
aadc --preset aggressive diagram.txt  # More permissive
aadc --preset relaxed diagram.txt     # Accept almost anything
aadc -P strict diagram.txt            # Short form
```

## Implementation

### Preset Resolution

```rust
impl Config {
    pub fn effective_min_score(&self) -> f64 {
        test_log!("DEBUG", "Resolving effective min_score");

        if let Some(preset) = self.preset {
            let score = match preset {
                Preset::Strict => 0.8,
                Preset::Normal => 0.5,
                Preset::Aggressive => 0.3,
                Preset::Relaxed => 0.1,
            };
            test_log!("DEBUG", "Using preset {:?} -> min_score={}", preset, score);
            score
        } else {
            test_log!("DEBUG", "Using explicit min_score={}", self.min_score);
            self.min_score
        }
    }
}
```

### Preset Descriptions for Help Text

```rust
impl Preset {
    pub fn description(&self) -> &'static str {
        match self {
            Preset::Strict => "Only apply edits when very confident (score >= 0.8). \
                              Best for production docs where mistakes are costly.",
            Preset::Normal => "Balanced threshold (score >= 0.5). \
                              Good for most use cases.",
            Preset::Aggressive => "Accept lower-confidence edits (score >= 0.3). \
                                   Useful when diagrams have unusual patterns.",
            Preset::Relaxed => "Accept almost any edit (score >= 0.1). \
                               Use with --diff to review changes.",
        }
    }
}
