```rust
pub fn print_preset_info(config: &Config, colors: &VerboseColors) {
    if let Some(preset) = config.preset {
        eprintln!(
            "{}Using preset: {:?}{} (min_score = {})",
            colors.header.render_str(""),
            preset,
            Style::reset(),
            config.effective_min_score()
