### File Discovery

```rust
use ignore::WalkBuilder;
use globset::{Glob, GlobSetBuilder};

pub fn discover_files(config: &Config) -> Result<Vec<PathBuf>, Error> {
    test_log!("INFO", "Discovering files with patterns: {}", config.glob);

    // Build glob matcher
    let mut glob_builder = GlobSetBuilder::new();
    for pattern in config.glob.split(',') {
        let pattern = pattern.trim();
        test_log!("DEBUG", "Adding glob pattern: {}", pattern);
        glob_builder.add(Glob::new(pattern)?);
    }
    let globs = glob_builder.build()?;

    let mut files = Vec::new();

    for path in &config.paths {
        test_log!("DEBUG", "Processing path: {:?}", path);

        if path.is_file() {
            // Direct file argument
            files.push(path.clone());
            continue;
        }

        if !path.is_dir() {
            test_log!("WARN", "Path does not exist: {:?}", path);
            continue;
        }

        // Build walker for directory
        let mut walker = WalkBuilder::new(path);
        walker.git_ignore(config.gitignore);
        walker.hidden(false);  // Don't skip hidden files by default

        if config.max_depth > 0 {
            walker.max_depth(Some(config.max_depth));
        }

        for entry in walker.build() {
            let entry = entry?;
            let entry_path = entry.path();

            if entry_path.is_file() {
                // Check if filename matches any glob
                if let Some(name) = entry_path.file_name() {
                    if globs.is_match(name) {
                        test_log!("DEBUG", "Matched: {:?}", entry_path);
                        files.push(entry_path.to_path_buf());
                    }
                }
            }
        }
    }

    test_log!("INFO", "Discovered {} files", files.len());
    Ok(files)
}
```

### Processing Loop with Progress

```rust
pub fn process_recursive(config: &Config) -> Result<RecursiveStats, Error> {
    let files = discover_files(config)?;

    if files.is_empty() {
        test_log!("WARN", "No files matched the glob pattern");
        eprintln!("Warning: No files matched pattern '{}' in specified paths", config.glob);
        return Ok(RecursiveStats::default());
    }

    let mut stats = RecursiveStats {
        files_processed: 0,
        files_modified: 0,
        files_skipped: 0,
        total_revisions: 0,
        errors: Vec::new(),
    };

    for (i, file) in files.iter().enumerate() {
        test_log!("INFO", "Processing file {}/{}: {:?}", i + 1, files.len(), file);

        if config.verbose {
            eprintln!("[{}/{}] Processing: {}", i + 1, files.len(), file.display());
        }

        match process_file(config, file) {
            Ok(file_stats) => {
                stats.files_processed += 1;
                stats.total_revisions += file_stats.revisions_applied;
                if file_stats.revisions_applied > 0 {
                    stats.files_modified += 1;
                }
            }
            Err(e) => {
                test_log!("ERROR", "Failed to process {:?}: {}", file, e);
                stats.errors.push((file.clone(), e.to_string()));
                stats.files_skipped += 1;
            }
        }
    }

    test_log!("INFO", "Recursive processing complete: {:?}", stats);
    Ok(stats)
}

#[derive(Debug, Default)]
pub struct RecursiveStats {
    pub files_processed: usize,
    pub files_modified: usize,
    pub files_skipped: usize,
    pub total_revisions: usize,
    pub errors: Vec<(PathBuf, String)>,
}
```

## Edge Cases

1. **No matching files**: Warn but don't error
2. **Permission denied**: Log error, continue with other files
3. **Symlink loops**: ignore crate handles this automatically
4. **Mixed files and directories**: Process both correctly
5. **Binary files**: Skip files that can't be read as UTF-8
6. **Empty directories**: Handle gracefully

