#[cfg(test)]
mod recursive_tests {
    use super::*;
    use tempfile::TempDir;
    use std::fs;

    #[test]
    fn test_glob_pattern_parsing() {
        test_log!("INFO", "Testing glob pattern parsing");

        let patterns = "*.txt,*.md, *.rst";  // Note extra space
        let parts: Vec<_> = patterns.split(',').map(|s| s.trim()).collect();

        assert_eq!(parts, vec!["*.txt", "*.md", "*.rst"]);
        test_log!("PASS", "Glob parsing works ✓");
    }

    #[test]
    fn test_file_discovery() {
        test_log!("INFO", "Testing file discovery");

        let tmpdir = TempDir::new().unwrap();
        fs::write(tmpdir.path().join("a.txt"), "content").unwrap();
        fs::write(tmpdir.path().join("b.md"), "content").unwrap();
        fs::write(tmpdir.path().join("c.rs"), "content").unwrap();

        let config = Config {
            recursive: true,
            glob: "*.txt,*.md".to_string(),
            gitignore: false,
            max_depth: 0,
            paths: vec![tmpdir.path().to_path_buf()],
            ..Default::default()
        };

        let files = discover_files(&config).unwrap();
        assert_eq!(files.len(), 2);  // a.txt and b.md, not c.rs

        test_log!("PASS", "File discovery works ✓");
    }

    #[test]
    fn test_max_depth_limit() {
        test_log!("INFO", "Testing max depth limit");

        let tmpdir = TempDir::new().unwrap();
        let deep = tmpdir.path().join("a").join("b").join("c");
        fs::create_dir_all(&deep).unwrap();
        fs::write(tmpdir.path().join("top.txt"), "").unwrap();
        fs::write(tmpdir.path().join("a/mid.txt"), "").unwrap();
        fs::write(deep.join("deep.txt"), "").unwrap();

        let config = Config {
            recursive: true,
            glob: "*.txt".to_string(),
            gitignore: false,
            max_depth: 2,
            paths: vec![tmpdir.path().to_path_buf()],
            ..Default::default()
        };

        let files = discover_files(&config).unwrap();
        // Should find top.txt and a/mid.txt but not a/b/c/deep.txt
        assert!(files.len() <= 2);
        test_log!("PASS", "Max depth works ✓");
    }

    #[test]
    fn test_gitignore_respected() {
        test_log!("INFO", "Testing .gitignore respect");

        let tmpdir = TempDir::new().unwrap();
        fs::write(tmpdir.path().join(".gitignore"), "ignored.txt\n").unwrap();
        fs::write(tmpdir.path().join("included.txt"), "").unwrap();
        fs::write(tmpdir.path().join("ignored.txt"), "").unwrap();

        let config = Config {
            recursive: true,
            glob: "*.txt".to_string(),
            gitignore: true,
            max_depth: 0,
            paths: vec![tmpdir.path().to_path_buf()],
            ..Default::default()
        };

        let files = discover_files(&config).unwrap();
        let names: Vec<_> = files.iter().filter_map(|p| p.file_name()).collect();

        assert!(!names.iter().any(|n| n == "ignored.txt"));
        test_log!("PASS", "Gitignore respected ✓");
    }
}
