        files_modified: 0,
        files_skipped: 0,
        total_revisions: 0,
        errors: Vec::new(),
    };

    for (i, file) in files.iter().enumerate() {
        test_log!("INFO", "Processing file {}/{}: {:?}", i + 1, files.len(), file);

        if config.verbose {
            eprintln!("[{}/{}] Processing: {}", i + 1, files.len(), file.display());
        }

        match process_file(config, file) {
            Ok(file_stats) => {
                stats.files_processed += 1;
                stats.total_revisions += file_stats.revisions_applied;
                if file_stats.revisions_applied > 0 {
                    stats.files_modified += 1;
                }
            }
            Err(e) => {
                test_log!("ERROR", "Failed to process {:?}: {}", file, e);
                stats.errors.push((file.clone(), e.to_string()));
                stats.files_skipped += 1;
            }
        }
    }

    test_log!("INFO", "Recursive processing complete: {:?}", stats);
    Ok(stats)
}

#[derive(Debug, Default)]
pub struct RecursiveStats {
    pub files_processed: usize,
    pub files_modified: usize,
    pub files_skipped: usize,
    pub total_revisions: usize,
    pub errors: Vec<(PathBuf, String)>,
}
```

## Edge Cases

1. **No matching files**: Warn but don't error
2. **Permission denied**: Log error, continue with other files
3. **Symlink loops**: ignore crate handles this automatically
4. **Mixed files and directories**: Process both correctly
5. **Binary files**: Skip files that can't be read as UTF-8
6. **Empty directories**: Handle gracefully

